INSERT INTO odjel (id, sifra, naziv, opis, vrijeme_kreiranja, vrijeme_azuriranja) VALUES
(1, 001, 'Interna medicina', 'Internisticka obrada odraslih pacijenata, tumacenje nalaza i koordinacija daljnje obrade.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(2, 002, 'Kardiologija', 'Dijagnostika i pracenje bolesti srca i krvnih zila.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(3, 003, 'Pulmologija', 'Obrada bolesti pluca, kaslja, astme, KOPB-a i otezana disanja.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(4, 004, 'Gastroenterologija', 'Obrada bolesti probavnog sustava, endoskopska dijagnostika i savjetovanje.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(5, 005, 'Endokrinologija', 'Obrada bolesti hormona, stitnjace, dijabetesa i metabolizma.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(6, 006, 'Nefrologija', 'Obrada bolesti bubrega, proteinurije i bubrežne funkcije.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(7, 007, 'Hematologija', 'Obrada anemija, poremecaja krvne slike i zgrusavanja.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(8, 008, 'Reumatologija', 'Obrada reumatskih, upalnih i autoimunih bolesti.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(9, 009, 'Ginekologija', 'Ginekoloski pregledi, ultrazvuk, PAPA test i savjetovanje.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(10, 010, 'Radiologija', 'Radioloska i slikovna dijagnostika.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(11, 011, 'Oftalmologija', 'Pregledi vida, ocnog tlaka i bolesti oka.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(12, 012, 'Urologija', 'Obrada tegoba mokrenja, prostate i bolesti mokracnog sustava.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(13, 013, 'Neurologija', 'Obrada glavobolja, vrtoglavica, neuropatija i neuroloskih ispada.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(14, 014, 'Ortopedija', 'Obrada bolesti i ozljeda kostiju, zglobova i kraljeznice.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(15, 015, 'Fizikalna medicina', 'Procjena funkcionalnog statusa i plan rehabilitacije.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(16, 016, 'Fizikalna terapija', 'Provodjenje rehabilitacijskih i terapijskih postupaka.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(17, 017, 'Pedijatrija', 'Pregledi djece, pracenje rasta i akutne tegobe.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(18, 018, 'Dermatologija', 'Pregledi koze, madeza, akni, osipa i veneroloska obrada.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(19, 019, 'Otorinolaringologija', 'Pregledi uha, grla, nosa, sinusa i sluha.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(20, 020, 'Opca kirurgija', 'Kirurski pregledi, rane, kontrola zahvata i konzultacije.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(21, 021, 'Mali kirurski zahvati', 'Manji ambulantni zahvati u lokalnoj anesteziji.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(22, 022, 'Psihijatrija', 'Psihijatrijska procjena, terapija i pracenje mentalnog zdravlja.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(23, 023, 'Anesteziologija', 'Predanestezioloska procjena i sedacija kod postupaka.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(24, 024, 'Medicina rada', 'Pregledi radnika, vozaca i procjena radne sposobnosti.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(25, 025, 'Laboratorij', 'Laboratorijska dijagnostika krvi, urina i biokemijskih parametara.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(26, 026, 'Patologija i citologija', 'Citoloska i patohistoloska analiza uzoraka.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(27, 027, 'Nutricionizam', 'Savjetovanje o prehrani, redukciji tjelesne mase i prehrani kod bolesti.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(28, 028, 'Sistematski pregledi', 'Preventivni, osnovni, prosireni i menadzerski pregledi.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(29, 029, 'Mamografija', 'Preventivna i dijagnosticka obrada dojki.', '2026-01-02 08:00:00', '2026-01-02 08:10:00'),
(30, 030, 'Ultrazvucna dijagnostika', 'Ultrazvucni pregledi razlicitih organskih sustava.', '2026-01-02 08:00:00', '2026-01-02 08:10:00');
